#!/usr/bin/env bash
set -euo pipefail

# vai agent loop — Claude Code, bare-shell mode
# Generated by `vai agent loop init`
#
# Repository : {{REPO_NAME}}
# Server     : {{SERVER_URL}}

# Change to the repository root (three levels up from .vai/agents/claude-code/).
cd "$(dirname "$0")/../../.."

# Load .env from the repository root so VAI_API_KEY and CLAUDE_CODE_OAUTH_TOKEN
# are available to every command in this script.
if [ -f .env ]; then
  set -a
  # shellcheck source=/dev/null
  source .env
  set +a
fi

: "${VAI_API_KEY:?VAI_API_KEY not set — add it to .env or export it}"
: "${CLAUDE_CODE_OAUTH_TOKEN:?CLAUDE_CODE_OAUTH_TOKEN not set — run 'claude setup-token' and add the token to .env}"

MAX_ITERATIONS="${MAX_ITERATIONS:-100}"
echo "Starting Claude Code agent loop for {{REPO_NAME}} (max ${MAX_ITERATIONS} iterations)"

for ((i = 1; i <= MAX_ITERATIONS; i++)); do
  echo ""
  echo "=== Iteration ${i}/${MAX_ITERATIONS} ==="

  if ! vai agent claim; then
    echo "No more issues to work on — loop complete."
    exit 0
  fi

  vai agent download ./work

  # Run Claude Code; pipe in the vai prompt.  The '|| true' prevents the loop
  # from aborting if claude exits non-zero (e.g. on soft model errors).
  vai agent prompt | claude -p \
    --allowedTools 'Read,Edit,Write,Bash,Glob,Grep' \
    || true

  if vai agent verify ./work; then
    vai agent submit ./work
  else
    echo "Verification failed — resetting workspace."
    vai agent reset
  fi

  rm -rf ./work
done

echo "Reached max iterations (${MAX_ITERATIONS}). Exiting."
